            "auth": {
                "secret_key": "",
                "algorithm": "HS256",
                "access_token_ttl": 3600,
                "refresh_token_ttl": 86400,
                "session_ttl": 7200,
                "max_sessions_per_user": 5,
                "rate_limit": {
                    "enabled": True,
                    "requests_per_minute": 60,
                    "burst_size": 10,
